def _new(self, im: core.ImagingCore) -> Image:
    new = Image()
    new.im = im
    new._mode = im.mode
    new._size = im.size
    if im.mode in ("P", "PA"):
        if self.palette:
            new.palette = self.palette.copy()
        else:
            from . import ImagePalette

            new.palette = ImagePalette.ImagePalette()
    new.info = self.info.copy()
    return new

# Context manager support
def __enter__(self):
    return self

def __exit__(self, *args):

